using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Tarefa #29 — pool genérica de prefabs de VFX (faíscas de impacto, poeira,
/// explosões, etc.) usada pelo feedback de combate (PlayerFeedback,
/// EnemyFeedback) para evitar Instantiate/Destroy repetidos durante combates
/// intensos.
///
/// <see cref="Spawn"/> devolve uma instância (reaproveitada da pool, se
/// disponível) já posicionada/rotacionada e activa, e agenda automaticamente
/// o seu retorno à pool — duração calculada a partir do ParticleSystem do
/// prefab (duration + startLifetime), ou <see cref="defaultLifetime"/> se o
/// prefab não tiver ParticleSystem.
///
/// Segue o mesmo padrão de singleton de AudioManager/GameSettings (Instance,
/// DontDestroyOnLoad, EnsureExists/isAutoFallback).
/// </summary>
public class VfxPoolManager : MonoBehaviour
{
    public static VfxPoolManager Instance { get; private set; }

    [Tooltip("Duração de vida usada quando o prefab não tem ParticleSystem (ou a duração não pode ser calculada).")]
    [Min(0.05f)] public float defaultLifetime = 1.5f;

    private readonly Dictionary<GameObject, Queue<GameObject>> _pools = new Dictionary<GameObject, Queue<GameObject>>();

    /// <summary>
    /// Marca instâncias criadas automaticamente por <see cref="EnsureExists"/>
    /// antes da primeira cena carregar (ver PlayerProgress.cs para a explicação
    /// completa — Tarefa #15 "GameBootstrap e singletons").
    /// </summary>
    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
            {
                Destroy(Instance.gameObject);
            }
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(VfxPoolManager) + " (Fallback)");
        var instance = go.AddComponent<VfxPoolManager>();
        instance.isAutoFallback = true;
    }

    /// <summary>
    /// Instancia (ou reaproveita da pool) "prefab" em "position"/"rotation", já
    /// activo, com os ParticleSystems reiniciados, e agenda o seu retorno
    /// automático à pool. Devolve null se "prefab" for null.
    /// </summary>
    public GameObject Spawn(GameObject prefab, Vector3 position, Quaternion? rotation = null)
    {
        if (prefab == null) return null;

        Quaternion rot = rotation ?? Quaternion.identity;
        GameObject instance = GetFromPool(prefab);

        if (instance == null)
        {
            instance = Instantiate(prefab, position, rot);
            instance.AddComponent<PooledVfxInstance>().SourcePrefab = prefab;
        }
        else
        {
            instance.transform.SetPositionAndRotation(position, rot);
            instance.SetActive(true);
        }

        RestartParticles(instance);

        float lifetime = ComputeLifetime(instance);
        instance.GetComponent<PooledVfxInstance>().BeginLifetime(lifetime);

        return instance;
    }

    /// <summary>Chamado por PooledVfxInstance ao fim da sua duração — devolve a instância à pool (desactivada) para reutilização futura.</summary>
    public void ReturnToPool(GameObject prefab, GameObject instance)
    {
        if (prefab == null || instance == null) return;

        instance.SetActive(false);

        if (!_pools.TryGetValue(prefab, out var queue))
        {
            queue = new Queue<GameObject>();
            _pools[prefab] = queue;
        }

        queue.Enqueue(instance);
    }

    private GameObject GetFromPool(GameObject prefab)
    {
        if (_pools.TryGetValue(prefab, out var queue))
        {
            while (queue.Count > 0)
            {
                var instance = queue.Dequeue();
                if (instance != null) return instance;
            }
        }

        return null;
    }

    private static void RestartParticles(GameObject instance)
    {
        var systems = instance.GetComponentsInChildren<ParticleSystem>(true);
        foreach (var ps in systems)
        {
            ps.Clear(true);
            ps.Play(true);
        }
    }

    private float ComputeLifetime(GameObject instance)
    {
        var root = instance.GetComponent<ParticleSystem>();
        if (root == null) root = instance.GetComponentInChildren<ParticleSystem>(true);

        if (root != null)
        {
            var main = root.main;
            float duration = main.duration + main.startLifetime.constantMax;
            if (duration > 0f) return duration;
        }

        return defaultLifetime;
    }
}
